import { MessageEvent } from '@nitrots/nitro-renderer';
import { TokensStoreParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TokenStoreParser';

export class TokensStoreEvent extends MessageEvent {
    constructor(callBack: (event: TokensStoreEvent) => void) {
        super(callBack, TokensStoreParser);
    }

    public getParser(): TokensStoreParser {
        return this.parser as TokensStoreParser;
    }
}

// Bridge to your React view (DiamondsStoreView listens to "store_tokens_shop")
export const tokensStoreEventCallback = (event: TokensStoreEvent) => {
    const parser = event.getParser();
    window.dispatchEvent(
        new CustomEvent('store_tokens_shop', {
            detail: {
                diamonds: parser.diamonds,
                items: parser.items,
            },
        })
    );
};
